/*\n  # Add Missing Competition Columns\n\n  1. Changes\n    - Add all missing columns that the admin form expects to insert\n    - These columns are required for the competition creation form to work\n    \n  2. New Columns Added\n    - `uid` (text) - Custom ID for competitions (used by the app)\n    - `imageurl` (text) - URL to competition image\n    - `prize_value` (numeric) - Value of the prize\n    - `ticket_price` (numeric) - Price per ticket (default 0.99)\n    - `total_tickets` (integer) - Total number of tickets available\n    - `tickets_sold` (integer) - Number of tickets sold (default 0)\n    - `start_date` (timestamptz) - When competition starts\n    - `end_date` (timestamptz) - When competition ends\n    - `draw_date` (timestamptz) - When the draw happens\n    - `is_instant_win` (boolean) - Whether this is an instant win competition\n    - `font_size_override` (text) - Custom font size for display\n    - `font_weight_override` (text) - Custom font weight for display\n    - `metadata_title` (text) - SEO metadata title\n    - `metadata_description` (text) - SEO metadata description\n    - `metadata_image` (text) - SEO metadata image URL\n    - `competitionended` (integer) - Flag for ended competitions (0=active, 1=ended)\n    - `crdate` (timestamptz) - Creation date (for ordering)\n    - `image_url` (text) - Alternative image URL column\n    \n  3. Notes\n    - All columns are nullable to avoid breaking existing data\n    - Default values set where appropriate\n    - No data migration needed as these are new columns\n*/\n\n-- Add uid column (custom ID used by the app)\nALTER TABLE competitions \nADD COLUMN IF NOT EXISTS uid text UNIQUE;
\n\n-- Add image columns\nALTER TABLE competitions \nADD COLUMN IF NOT EXISTS imageurl text,\nADD COLUMN IF NOT EXISTS image_url text;
\n\n-- Add prize and ticket columns\nALTER TABLE competitions \nADD COLUMN IF NOT EXISTS prize_value numeric,\nADD COLUMN IF NOT EXISTS ticket_price numeric DEFAULT 0.99,\nADD COLUMN IF NOT EXISTS total_tickets integer,\nADD COLUMN IF NOT EXISTS tickets_sold integer DEFAULT 0;
\n\n-- Add date columns\nALTER TABLE competitions \nADD COLUMN IF NOT EXISTS start_date timestamptz DEFAULT now(),\nADD COLUMN IF NOT EXISTS end_date timestamptz,\nADD COLUMN IF NOT EXISTS draw_date timestamptz;
\n\n-- Add feature flags\nALTER TABLE competitions \nADD COLUMN IF NOT EXISTS is_instant_win boolean DEFAULT false;
\n\n-- Add display customization columns\nALTER TABLE competitions \nADD COLUMN IF NOT EXISTS font_size_override text,\nADD COLUMN IF NOT EXISTS font_weight_override text;
\n\n-- Add SEO metadata columns\nALTER TABLE competitions \nADD COLUMN IF NOT EXISTS metadata_title text,\nADD COLUMN IF NOT EXISTS metadata_description text,\nADD COLUMN IF NOT EXISTS metadata_image text;
\n\n-- Add legacy columns for compatibility\nALTER TABLE competitions \nADD COLUMN IF NOT EXISTS competitionended integer DEFAULT 0,\nADD COLUMN IF NOT EXISTS crdate timestamptz DEFAULT now();
\n\n-- Create index on uid for faster lookups\nCREATE INDEX IF NOT EXISTS idx_competitions_uid ON competitions(uid);
\n\n-- Create index on competitionended for filtering\nCREATE INDEX IF NOT EXISTS idx_competitions_ended ON competitions(competitionended);
\n\n-- Create index on crdate for ordering\nCREATE INDEX IF NOT EXISTS idx_competitions_crdate ON competitions(crdate);
\n;
